using Ledgerly.Domain.Common; using Ledgerly.Domain.Enums; using Ledgerly.Domain.Exceptions; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Domain.Entities; public sealed class Invoice:OrganizationScopedEntity{ private readonly List<InvoiceLine> _lines=new(); public Guid CustomerId{get;private set;} public string InvoiceNumber{get;private set;}=string.Empty; public DateOnly IssueDate{get;private set;} public DateOnly DueDate{get;private set;} public CurrencyCode Currency{get;private set;} public Guid IncomeAccountId{get;private set;} public Guid ReceivableAccountId{get;private set;} public InvoiceStatus Status{get;private set;} public Money Subtotal{get;private set;} public Money TaxTotal{get;private set;} public Money TotalAmount{get;private set;} public Money AmountPaid{get;private set;} public Guid? JournalEntryId{get;private set;} public IReadOnlyCollection<InvoiceLine> Lines=>_lines.AsReadOnly(); private Invoice(){Currency=new CurrencyCode("USD");Subtotal=TaxTotal=TotalAmount=AmountPaid=new Money(0m,Currency);} public Invoice(Guid organizationId,Guid customerId,string invoiceNumber,DateOnly issueDate,DateOnly dueDate,CurrencyCode currency,Guid incomeAccountId,Guid receivableAccountId):base(organizationId){ if(customerId==Guid.Empty)throw new DomainException("Customer is required."); CustomerId=customerId; InvoiceNumber=invoiceNumber.Trim(); IssueDate=issueDate; DueDate=dueDate; Currency=currency; IncomeAccountId=incomeAccountId; ReceivableAccountId=receivableAccountId; Subtotal=TaxTotal=TotalAmount=AmountPaid=new Money(0m,Currency); Status=InvoiceStatus.Draft;} public InvoiceLine AddLine(string description,decimal quantity,Money unitPrice,Guid? taxCodeId,Money discount){ if(Status!=InvoiceStatus.Draft)throw new DomainException("Invoice is not in draft status."); var line=new InvoiceLine(Id,description,quantity,unitPrice,taxCodeId,discount); if(line.GetNetAmount().Amount<0m)throw new DomainException("Line discount cannot exceed line total."); _lines.Add(line); Touch(); return line;} public void Send(IReadOnlyDictionary<Guid,decimal> taxRates){ if(Status!=InvoiceStatus.Draft)throw new DomainException("Invoice is not in draft status."); if(_lines.Count==0)throw new DomainException("Invoice must have at least one line before sending."); var a=CalculateAmounts(taxRates); Subtotal=a.Subtotal; TaxTotal=a.Tax; TotalAmount=a.Total; Status=InvoiceStatus.Sent; Touch();} public void AttachJournalEntry(Guid journalEntryId){JournalEntryId=journalEntryId;Touch();} public void RecordPayment(Money paymentAmount){ if(Status!=InvoiceStatus.Sent&&Status!=InvoiceStatus.PartiallyPaid)throw new DomainException("Payments can only be recorded for sent or partially paid invoices."); if(paymentAmount.Amount>(TotalAmount-AmountPaid).Amount)throw new DomainException("Payment amount exceeds balance due."); AmountPaid+=paymentAmount; Status=AmountPaid.Amount>=TotalAmount.Amount?InvoiceStatus.Paid:InvoiceStatus.PartiallyPaid; Touch();} public void Void(){ if(Status==InvoiceStatus.Paid)throw new DomainException("Paid invoices cannot be voided."); Status=InvoiceStatus.Void; Touch();} public InvoiceAmounts CalculateAmounts(IReadOnlyDictionary<Guid,decimal> taxRates){ var zero=new Money(0m,Currency); var sub=zero; var tax=zero; foreach(var line in _lines){ sub+=line.GetNetAmount(); if(line.TaxCodeId is Guid id&&taxRates.TryGetValue(id,out var rate)) tax+=line.GetTaxAmount(rate);} return new InvoiceAmounts(sub,tax,sub+tax);} } public readonly record struct InvoiceAmounts(Money Subtotal,Money Tax,Money Total);
